// File: src/vunderstory-cli.mjs
import { execFileSync } from "node:child_process";
import { access } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { openAppShell } from "./app-shell.mjs";
import { captureIntentDecision } from "./intent-decisions.mjs";
import { addEvidence, listEvidence } from "./evidence-store.mjs";
import { loadIssueGraph } from "./work-graph.mjs";
import { continuationDecision, renderContinuationDecisionText } from "./continuation-policy.mjs";
import { loadProviderSettings } from "./settings-provider.mjs";
import {
  bootstrapRuntimeEnvelope,
  loadRuntimeManifest,
  readHermesScopedContext,
  renderRuntimeDoctorText,
  runtimeManifestPath
} from "./runtime-bootstrap.mjs";
import { defaultBudgetFor, selectModelRoute } from "./model-router.mjs";
import { CoordinationMailbox } from "./mailbox.mjs";
import { buildContextPackFromRuntime, renderContextPackPreview } from "./context-pack.mjs";

export async function runVunderstoryCli(argv = process.argv.slice(2), env = process.env) {
  const options = parseArgs(argv);
  const repoPath = path.resolve(options.values.repo ?? process.cwd());
  const stateDir = path.resolve(options.values["state-dir"] ?? path.join(repoPath, ".vunderstory", "state"));
  const command = options.command ?? (options.flags.yolo ? "yolo" : null);
  const context = { repoPath, stateDir, json: options.flags.json === true, details: options.flags.details === true };

  if (!command) return renderWelcome(await shellContext(context), context);
  if (command === "projects") return renderProjects(await shellContext(context), context);
  if (command === "status") return renderStatus(await statusContext(context), context);
  if (command === "work") return renderWork(await statusContext(context), context);
  if (command === "ask") return renderAsk(await statusContext(context), options.positionals.join(" "), context);
  if (command === "intent") return renderIntent(await recordIntent({ ...context, message: options.positionals.join(" ") }), context);
  if (command === "evidence") return renderEvidence(await handleEvidence({ ...context, options }), context);
  if (command === "runtime") return renderRuntime(await handleRuntime({ ...context, options }), context);
  if (command === "continue") return renderContinue(await continuationContext(context), context);
  if (command === "doctor") return renderDoctor(await doctor(context), context);
  if (command === "yolo") return renderYolo(await yoloContext(context), context);
  throw new Error(`unknown vunderstory command: ${command}`);
}

async function shellContext({ repoPath, stateDir }) {
  return openAppShell({ repoPath, stateDir });
}

async function statusContext({ repoPath, stateDir }) {
  const shell = await shellContext({ repoPath, stateDir });
  const graph = await loadIssueGraph({ issueDir: path.join(repoPath, "docs/issues/vunderstory-bootstrap-harness") });
  const ready = graph.readyQueue();
  const blocked = graph.blocked();
  const branch = currentBranch(repoPath);
  const worktree = currentWorktree(repoPath);
  return { shell, graph, ready, blocked, branch, worktree };
}

async function continuationContext(context) {
  const status = await statusContext(context);
  const next = status.ready[0] ?? null;
  const gates = await readContinuationGates(context, status, next);
  const decision = continuationDecision({
    runtime_event: { type: "codex_stop_hook", work_item_id: next?.id ?? null },
    graph: {
      ready_count: status.ready.length,
      next_ready_item: next?.id ?? null,
      dependencies_satisfied: gates.dependencies_satisfied,
      prototype_gate_satisfied: gates.prototype_gate_satisfied
    },
    claim: {
      can_claim: Boolean(next),
      branch: next ? `codex/${next.id.toLowerCase()}` : null,
      worktree_path: next ? `.worktrees/${next.id.toLowerCase()}` : null,
      heartbeat: "fresh"
    },
    evidence: { gates_passed: gates.evidence_gates_passed },
    budget: { route_present: gates.route_present, available: gates.budget_available },
    settings: {
      provider_configured: gates.provider_configured,
      runtime_configured: gates.runtime_configured
    },
    policy: { inside_approved_envelope: gates.inside_approved_envelope }
  });
  return { ...status, decision, next, gates };
}

async function yoloContext(context) {
  const continuation = await continuationContext(context);
  const missingDoctor = (await doctor(context)).tools.filter((tool) => !tool.available && ["rg", "gh"].includes(tool.name));
  const blockedReasons = [];
  if (continuation.decision.outcome !== "continue") blockedReasons.push(continuation.decision.reason);
  if (missingDoctor.some((tool) => tool.name === "rg")) blockedReasons.push("preferred search tool rg is missing");
  return {
    ...continuation,
    mode: "full auto inside approved plan",
    blockedReasons,
    can_continue: blockedReasons.length === 0
  };
}

async function recordIntent({ repoPath, stateDir, message }) {
  if (!message) throw new Error("intent requires a message");
  return captureIntentDecision({
    stateDir,
    repoPath,
    text: message,
    decision: "CLI intent captured for Vunderstory Assistant planning.",
    speaker: "founder",
    source: {
      kind: "cli",
      conversation_id: "vunderstory-cli",
      message_id: `cli-${Date.now()}`
    },
    linked_artifact: {
      kind: "prd",
      path: "docs/prds/2026-04-28-vunderstory-bootstrap-harness.md",
      refs: ["FR25", "FR26", "FR28", "FR35", "FR36", "S038"]
    }
  });
}

async function readContinuationGates({ repoPath, stateDir }, status, next) {
  const settings = await readSettingsGates(stateDir);
  const runtimeConfigured = settings.runtime_configured || await hasFreshRuntimeEnvelope(stateDir);
  return {
    dependencies_satisfied: Boolean(next) && (next.blockers?.length ?? 0) === 0,
    prototype_gate_satisfied: await fileExists(path.join(repoPath, "docs/architecture/ui-prototype-approval-gate-contract.md")),
    evidence_gates_passed: await fileExists(path.join(repoPath, "docs/fixtures/learning-loop/2026-04-26-broken-run.manifest.json")),
    route_present: await fileExists(path.join(repoPath, "docs/architecture/model-router-run-budget-contract.md")),
    budget_available: await fileExists(path.join(repoPath, "src/model-router.mjs")),
    provider_configured: settings.provider_configured,
    runtime_configured: runtimeConfigured,
    inside_approved_envelope: status.shell.product_envelope?.evaluation?.state === "ready"
  };
}

async function hasFreshRuntimeEnvelope(stateDir) {
  try {
    const manifest = await loadRuntimeManifest({ stateDir });
    return manifest.hermes.status === "fresh" && manifest.pi.status === "fresh";
  } catch (error) {
    if (error.code === "ENOENT") return false;
    throw error;
  }
}

async function readSettingsGates(stateDir) {
  const parsed = await loadProviderSettings({ stateDir });
  return {
    provider_configured: parsed.provider_configured === true,
    runtime_configured: parsed.runtime_configured === true
  };
}

async function fileExists(target) {
  try {
    await access(target);
    return true;
  } catch {
    return false;
  }
}

async function handleEvidence({ repoPath, stateDir, options }) {
  const subcommand = options.positionals[0];
  if (subcommand !== "add") throw new Error("evidence supports: add <path> --for <work-item>");
  const evidencePath = options.positionals[1];
  const workItemId = options.values.for;
  if (options.flags["dry-run"]) {
    return { dry_run: true, path: evidencePath, work_item_id: workItemId, source_mutated: false };
  }
  return addEvidence({ stateDir, repoPath, evidencePath, workItemId, note: options.values.note ?? "" });
}

async function handleRuntime({ repoPath, stateDir, options }) {
  const subcommand = options.positionals[0] ?? "status";
  if (subcommand === "bootstrap") {
    return {
      action: "bootstrap",
      manifest: await bootstrapRuntimeEnvelope({ repoPath, stateDir })
    };
  }
  if (subcommand === "status") {
    try {
      return { action: "status", manifest: await loadRuntimeManifest({ stateDir }) };
    } catch (error) {
      if (error.code === "ENOENT") return { action: "status", manifest: null, blocker: "runtime envelope has not been bootstrapped" };
      throw error;
    }
  }
  if (subcommand === "context") {
    const scope = options.positionals[1] ?? "continuity";
    return {
      action: "context",
      item: await readHermesScopedContext({ stateDir, scope })
    };
  }
  if (subcommand === "context-pack") {
    const workItemId = options.positionals[1] ?? "S019";
    const role = options.values.role ?? "builder";
    const graph = await loadIssueGraph({ issueDir: path.join(repoPath, "docs/issues/vunderstory-bootstrap-harness") });
    const workItem = graph.view(workItemId);
    const route = selectModelRoute({ workItemId, taskClass: "coding", risk: "medium", capabilityIds: ["C5", "C10"] });
    const budget = defaultBudgetFor("coding");
    const mailbox = new CoordinationMailbox();
    mailbox.post({
      type: "context_needed",
      sender_role: "builder",
      recipient_role: "planner",
      work_item_id: workItemId,
      run_id: `run-${workItemId.toLowerCase()}-context-pack`,
      payload: { summary: "Generate scoped memory context pack preview." }
    });
    const pack = await buildContextPackFromRuntime({
      repoPath,
      stateDir,
      workItem: {
        ...workItem,
        objective: "O2",
        capability: "C5"
      },
      prdSlice: {
        id: "FR9",
        refs: ["docs/prds/2026-04-28-vunderstory-bootstrap-harness.md#FR9"]
      },
      graphState: {
        founder_state: workItem.founder_state,
        blockers: workItem.blockers
      },
      evidence: [{ id: "runtime-manifest", path: path.relative(repoPath, runtimeManifestPath({ stateDir })) }],
      mailboxMessages: mailbox.messages,
      role,
      taskClass: "coding",
      modelRoute: route,
      budget
    });
    return {
      action: "context-pack",
      pack,
      preview: renderContextPackPreview(pack)
    };
  }
  throw new Error("runtime supports: status | bootstrap | context [scope] | context-pack [work-item-id] [--role role]");
}

function renderWelcome(shell, context) {
  if (context.json) return shell;
  return [
    "Vunderstory",
    "Local-first product harness",
    "",
    row("Project", shell.selected_project.name),
    row("Assistant", "memory-backed"),
    row("Mode", "work locally"),
    row("Branch", currentBranch(context.repoPath)),
    row("Worktree", currentWorktree(context.repoPath)),
    "",
    "What do you want to do?",
    "  ask       Ask the assistant",
    "  status    See blockers and active work",
    "  intent    Start a new product intent",
    "  continue  Check whether overnight work can proceed"
  ].join("\n");
}

function renderProjects(shell, context) {
  if (context.json) return shell.projects;
  return ["Projects", ...shell.projects.map((project) =>
    `${project.selected ? ">" : " "} ${project.name}  ${project.conversation_count} chats  ${project.risk_profile}`
  )].join("\n");
}

function renderStatus(status, context) {
  if (context.json) {
    return {
      project: status.shell.selected_project,
      ready: status.ready,
      blocked: status.blocked,
      branch: status.branch,
      worktree: status.worktree,
      learning_health: status.shell.learning_health
    };
  }
  const ready = status.ready.slice(0, 5).map((item) => `  ${item.id} ${item.title}`).join("\n") || "  No ready work";
  const blocked = status.blocked.slice(0, 5).map((item) => `  ${item.id} ${item.title}: blocked by ${item.blockers.join(", ") || "visible health/policy"}`).join("\n") || "  No blockers";
  return [
    `Project: ${status.shell.selected_project.name}`,
    `Branch: ${status.branch}`,
    `Worktree: ${status.worktree}`,
    "",
    "Ready",
    ready,
    "",
    "Blocked",
    blocked,
    "",
    "Learning health",
    `  ${status.shell.learning_health.founder_label}: ${status.shell.learning_health.founder_summary}`,
    "",
    "Next safe action",
    `  ${status.ready[0] ? `Continue with ${status.ready[0].id} ${status.ready[0].title}.` : "No ready work remains."}`
  ].join("\n");
}

function renderWork(status, context) {
  if (context.json) return { ready: status.ready, blocked: status.blocked };
  return [
    "Work graph",
    `Ready: ${status.ready.length}`,
    `Blocked: ${status.blocked.length}`,
    ...status.ready.map((item) => `  ready ${item.id} ${item.title}`),
    ...status.blocked.slice(0, 10).map((item) => `  blocked ${item.id} ${item.title}`)
  ].join("\n");
}

function renderAsk(status, message, context) {
  const lower = message.toLowerCase();
  const answer = lower.includes("blocked")
    ? blockedAnswer(status)
    : `I can see ${status.ready.length} ready work item(s). The next safe action is ${status.ready[0]?.id ?? "none"}.`;
  if (context.json) return { assistant: "Vunderstory Assistant", question: message, answer };
  return ["Vunderstory Assistant", answer].join("\n");
}

function renderIntent(record, context) {
  if (context.json) return record;
  return [
    "Captured intent",
    row("Goal", record.summary),
    row("Artifact", `${record.linked_artifact.kind}: ${record.linked_artifact.path}`),
    row("Risk", "local-only until external writes are requested"),
    "",
    "Next",
    "I will keep this behind the same project state, policy, evidence, and audit contracts as the cockpit."
  ].join("\n");
}

function renderEvidence(record, context) {
  if (context.json) return record;
  return [
    record.dry_run ? "Evidence dry run" : "Evidence attached",
    row("Work item", record.work_item_id),
    row("Path", record.path),
    row("Source mutated", String(record.source_mutated))
  ].join("\n");
}

function renderContinue(result, context) {
  if (context.json) return { decision: result.decision, next: result.next };
  return [
    `Continuation decision: ${result.decision.outcome}`,
    "",
    "Why",
    `  ${renderContinuationDecisionText(result.decision)}`,
    "",
    "Next slice",
    `  ${result.next ? `${result.next.id} ${result.next.title}` : "No active or ready work remains."}`
  ].join("\n");
}

function renderYolo(result, context) {
  if (context.json) return result;
  const checks = result.decision.outcome === "complete"
    ? ["✓ no active or ready work remains"]
    : result.can_continue
    ? ["✓ policy envelope allows continuation", "✓ work graph has eligible local work", "✓ worktree contract is active"]
    : result.blockedReasons.map((reason) => `✗ ${reason}`);
  return [
    "Vunderstory --yolo",
    row("Mode", result.mode),
    row("Decision", result.decision.outcome),
    "",
    "EVALS",
    ...checks.map((check) => `  ${check}`),
    "",
    result.can_continue
      ? `Next: ${result.next.id} ${result.next.title}`
      : result.decision.outcome === "complete"
        ? "Nothing to continue: no active or ready work remains."
      : "Stopped: next action needs setup, policy, dependency, or approval."
  ].join("\n");
}

function renderRuntime(result, context) {
  if (context.json) return result;
  if (result.action === "context") {
    return [
      "Scoped memory context",
      row("Scope", result.item.scope),
      row("Target", result.item.target_memory),
      row("Source", `${result.item.source.id} ${result.item.source.source_path}`),
      row("Promotion", result.item.source.promotion_status),
      row("Confidence", result.item.source.confidence)
    ].join("\n");
  }
  if (result.action === "context-pack") {
    return [
      "Memory context pack preview",
      row("Work item", result.preview.work_item),
      row("Objective", result.preview.objective),
      row("Capability", result.preview.capability),
      row("Memory contrib", String(result.preview.hermes_contributed)),
      row("Project truth", String(result.preview.project_truth)),
      row("Excluded mem", String(result.preview.excluded_memory)),
      row("Conflicts", String(result.preview.memory_conflicts)),
      row("Mailbox msgs", String(result.preview.mailbox_messages))
    ].join("\n");
  }
  if (!result.manifest) return `Runtime envelope\n  blocked: ${result.blocker}`;
  return renderRuntimeDoctorText(result.manifest);
}

function renderDoctor(report, context) {
  if (context.json) return report;
  return [
    "Vunderstory doctor",
    ...report.tools.map((tool) => `${tool.available ? "✓" : "✗"} ${tool.name.padEnd(3)} ${tool.available ? tool.path : "missing"} — ${tool.preference}`),
    "",
    report.runtime.manifest
      ? renderRuntimeDoctorText(report.runtime.manifest)
      : `Runtime envelope\n  blocked: ${report.runtime.blocker}`
  ].join("\n");
}

function blockedAnswer(status) {
  if (status.blocked.length === 0) return "Nothing is blocked right now.";
  const lines = status.blocked.slice(0, 5).map((item, index) =>
    `${index + 1}. ${item.title} is blocked by ${item.blockers.join(", ") || "a visible policy or health state"}.`
  );
  return [`${status.blocked.length} work item(s) are blocked:`, ...lines].join("\n");
}

async function doctor({ stateDir }) {
  const tools = [
    ["bun", "prefer over node/npm when the project supports it"],
    ["rg", "prefer over grep"],
    ["fd", "prefer over find"],
    ["sd", "prefer over sed for simple replacements"],
    ["jq", "use for JSON inspection"],
    ["gh", "use only after external-write approval"]
  ];
  const report = tools.map(([name, preference]) => {
    const found = which(name);
    return { name, preference, available: Boolean(found), path: found };
  });
  let runtime;
  try {
    runtime = { manifest: await loadRuntimeManifest({ stateDir }) };
  } catch (error) {
    if (error.code !== "ENOENT") throw error;
    runtime = { manifest: null, blocker: "runtime envelope has not been bootstrapped" };
  }
  return { tools: report, runtime };
}

function currentBranch(repoPath) {
  return safeExec("git", ["branch", "--show-current"], repoPath) || "unknown";
}

function currentWorktree(repoPath) {
  const top = safeExec("git", ["rev-parse", "--show-toplevel"], repoPath);
  if (!top) return "unknown";
  return top === repoPath ? "repo root" : top;
}

function which(command) {
  return safeExec("which", [command], process.cwd());
}

function safeExec(command, args, cwd, options = {}) {
  try {
    return execFileSync(command, args, { cwd, encoding: "utf8", stdio: ["ignore", "pipe", "ignore"], ...options }).trim();
  } catch {
    return "";
  }
}

function row(label, value) {
  return `${label.padEnd(12)} ${value}`;
}

function parseArgs(argv) {
  const flags = {};
  const values = {};
  const positionals = [];
  let command = null;
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === "--yolo") {
      flags.yolo = true;
      command = "yolo";
      continue;
    }
    if (arg.startsWith("--")) {
      const name = arg.slice(2);
      if (["json", "details", "dry-run"].includes(name)) {
        flags[name] = true;
      } else {
        values[name] = argv[i + 1];
        i += 1;
      }
      continue;
    }
    if (!command) command = arg;
    else positionals.push(arg);
  }
  return { command, flags, values, positionals };
}

async function main() {
  const result = await runVunderstoryCli();
  process.stdout.write(`${typeof result === "string" ? result : JSON.stringify(result, null, 2)}\n`);
}

const isCli = process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (isCli) {
  main().catch((error) => {
    console.error(error.message);
    process.exit(1);
  });
}

export { main };

// File: src/policy-classifier.mjs
import { writeFile } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { recordEvidenceEvent } from "./evidence-ledger.mjs";

export const POLICY_CLASSIFIER_SCHEMA_VERSION = 1;
export const POLICY_CLASSES = Object.freeze(["safe_auto_ready", "bulk_review", "critical_approval", "blocking_work_item"]);
export const DEFAULT_CRITICAL_FLAGS = Object.freeze([
  "external_write",
  "deployment",
  "money",
  "secrets",
  "sensitive_memory_promotion",
  "destructive_command",
  "irreversible_migration",
  "security_boundary",
  "project_truth_change"
]);

export function classifyPolicyDecision({ candidate, policy = {}, now = new Date().toISOString() }) {
  const normalized = normalizeCandidate(candidate);
  const criticalFlags = policy.critical_flags ?? DEFAULT_CRITICAL_FLAGS;
  const hasCriticalFlag = normalized.risk_flags.some((flag) => criticalFlags.includes(flag));
  const categoryEnabled = (policy.safe_auto_enabled_categories ?? []).includes(normalized.action_category);
  const sameClassObservationStats = observationStats(normalized.evidence.observations);
  const evidenceSufficient = normalized.evidence.deterministic_local_check === true
    || (sameClassObservationStats.count >= 3 && (sameClassObservationStats.sessions >= 2 || sameClassObservationStats.days >= 2));
  const evidenceQuality = normalized.evidence.source_trace === true && normalized.evidence.artifact_refs.length > 0;
  const capabilityLinked = Boolean(
    normalized.capability_link.objective_id
      && normalized.capability_link.outcome_id
      && normalized.capability_link.capability_id
      && normalized.capability_link.expected_benefit
  );
  const verificationPassed = normalized.verification.observation_only === true
    || normalized.verification.passed === true;
  const reversible = Boolean(normalized.rollback?.type && normalized.rollback?.description);
  const blastRadiusScoped = normalized.scope.local_first === true && Boolean(normalized.scope.project_id && normalized.scope.work_item_id);
  const confidencePassed = normalized.confidence >= 0.85;
  const recurredAfterSafeAuto = normalized.recurrence.after_safe_auto_change === true;
  const trendNotImproving = normalized.recurrence.thirty_day_trend_improved === false;

  const thresholdResults = {
    category_enabled: gate(categoryEnabled, categoryEnabled ? "Safe-auto is enabled for this action category." : "Safe-auto is disabled for this action category."),
    risk_class: gate(!hasCriticalFlag, hasCriticalFlag ? `Critical flag present: ${normalized.risk_flags.find((flag) => criticalFlags.includes(flag))}.` : "No critical risk flags are present."),
    evidence_sufficiency: gate(evidenceSufficient, evidenceSufficient ? "Deterministic check or repeated observations meet ADR-0003." : "Needs deterministic local proof or three same-class observations across two sessions/days."),
    evidence_quality: gate(evidenceQuality, evidenceQuality ? "Evidence includes source trace and concrete artifact refs." : "Evidence needs both source trace and concrete artifact refs."),
    confidence: gate(confidencePassed, `Classifier confidence is ${normalized.confidence.toFixed(2)}; required minimum is 0.85.`),
    capability_link: gate(capabilityLinked, capabilityLinked ? "Objective, outcome, capability, and benefit are linked." : "Objective, outcome, capability, or expected benefit is missing."),
    verification: gate(verificationPassed, verificationPassed ? "Verification passed or candidate is observation-only." : "Required verification has not passed."),
    reversibility: gate(reversible, reversible ? "Rollback path is defined." : "Rollback path is missing."),
    blast_radius: gate(blastRadiusScoped, blastRadiusScoped ? "Change is local-first and scoped to one project/work item." : "Blast radius is not scoped enough."),
    recurrence: gate(!recurredAfterSafeAuto, recurredAfterSafeAuto ? "Same friction class recurred after a safe-auto change." : "No safe-auto recurrence downgrade applies."),
    thirty_day_trend: gate(!trendNotImproving, trendNotImproving ? "30-day trend did not improve after the prior change." : "30-day trend does not block this decision.")
  };

  let policyClass = "bulk_review";
  let downgradeReason = null;
  if (hasCriticalFlag) {
    policyClass = "critical_approval";
  } else if (trendNotImproving) {
    policyClass = "blocking_work_item";
    downgradeReason = "thirty_day_trend_not_improving";
  } else if (recurredAfterSafeAuto) {
    policyClass = "bulk_review";
    downgradeReason = "friction_recurred_after_safe_auto";
  } else if (Object.values(thresholdResults).every((result) => result.passed)) {
    policyClass = "safe_auto_ready";
  }

  const decision = {
    schema_version: POLICY_CLASSIFIER_SCHEMA_VERSION,
    id: `policy-${normalized.id}`,
    candidate_id: normalized.id,
    work_item_id: normalized.work_item_id,
    action_category: normalized.action_category,
    friction_class: normalized.friction_class,
    policy_class: policyClass,
    risk: {
      flags: normalized.risk_flags,
      critical_flags_matched: normalized.risk_flags.filter((flag) => criticalFlags.includes(flag))
    },
    evidence: normalized.evidence,
    threshold_results: thresholdResults,
    rationale: rationaleFor({ policyClass, normalized, thresholdResults, hasCriticalFlag, recurredAfterSafeAuto, trendNotImproving }),
    founder_summary: founderSummaryFor({ policyClass, normalized, hasCriticalFlag, recurredAfterSafeAuto, trendNotImproving }),
    rollback: normalized.rollback,
    capability_link: normalized.capability_link,
    verification: normalized.verification,
    requires_founder_approval: policyClass === "critical_approval",
    bulk_review_key: policyClass === "bulk_review" ? bulkReviewKey(normalized) : null,
    downgrade_reason: downgradeReason,
    expires_at: expiryFrom(now),
    audit: {
      actor: "vunderstory-policy-classifier",
      action: "classify_policy_candidate",
      input_candidate_id: normalized.id,
      output_policy_class: policyClass,
      rationale_refs: Object.entries(thresholdResults).filter(([, result]) => !result.passed).map(([name]) => name)
    },
    timestamp: now
  };

  return Object.freeze(decision);
}

export function groupBulkReviewCandidates(decisions) {
  const groups = new Map();
  for (const decision of decisions.filter((candidate) => candidate.policy_class === "bulk_review")) {
    const key = decision.bulk_review_key;
    const current = groups.get(key) ?? {
      group_key: key,
      policy_class: "bulk_review",
      action_category: decision.action_category,
      friction_class: decision.friction_class,
      decision_ids: [],
      candidate_ids: [],
      founder_summary: `Bulk review ${decision.action_category} items for ${decision.friction_class}.`
    };
    current.decision_ids.push(decision.id);
    current.candidate_ids.push(decision.candidate_id);
    groups.set(key, current);
  }
  return Array.from(groups.values());
}

export async function recordPolicyDecisionAudit({ stateDir, repoPath = process.cwd(), decision, now = new Date().toISOString() }) {
  const ledger = await recordEvidenceEvent({
    stateDir,
    repoPath,
    claim: {
      id: `claim-${decision.id}`,
      work_item_id: decision.work_item_id,
      claim_type: "policy_decision",
      statement: `Policy classifier assigned ${decision.policy_class} to ${decision.candidate_id}.`,
      status: "open",
      timestamp: now
    },
    audit: [
      {
        id: `audit-${decision.id}`,
        actor: "vunderstory-policy-classifier",
        action: "classify_policy_candidate",
        work_item_id: decision.work_item_id,
        input: {
          candidate_id: decision.candidate_id,
          action_category: decision.action_category,
          friction_class: decision.friction_class
        },
        output: {
          policy_class: decision.policy_class,
          requires_founder_approval: decision.requires_founder_approval,
          failed_gates: Object.entries(decision.threshold_results).filter(([, result]) => !result.passed).map(([name]) => name)
        },
        linked_evidence_ids: decision.evidence.artifact_refs.filter((ref) => ref.startsWith("evidence-")),
        policy_classification: decision,
        timestamp: now
      }
    ],
    now
  });

  await writeFile(path.join(os.tmpdir(), "vunderstory-s021-policy-decision.json"), `${JSON.stringify(decision, null, 2)}\n`);
  return ledger;
}

