function normalizeCandidate(input) {
  return {
    id: required(input.id, "candidate id"),
    work_item_id: input.work_item_id ?? "S021",
    action_category: required(input.action_category, "action category"),
    friction_class: input.friction_class ?? "unknown",
    risk_flags: array(input.risk_flags),
    confidence: Number(input.confidence ?? 0),
    evidence: {
      deterministic_local_check: input.evidence?.deterministic_local_check === true,
      source_trace: input.evidence?.source_trace === true,
      artifact_refs: array(input.evidence?.artifact_refs),
      observations: array(input.evidence?.observations).map((observation) => ({
        session_id: observation.session_id ?? "unknown",
        day: observation.day ?? "unknown"
      }))
    },
    capability_link: input.capability_link ?? {},
    verification: {
      required: array(input.verification?.required),
      passed: input.verification?.passed === true,
      observation_only: input.verification?.observation_only === true
    },
    rollback: input.rollback ?? null,
    scope: {
      local_first: input.scope?.local_first === true,
      project_id: input.scope?.project_id ?? null,
      work_item_id: input.scope?.work_item_id ?? input.work_item_id ?? null
    },
    recurrence: {
      after_safe_auto_change: input.recurrence?.after_safe_auto_change === true,
      thirty_day_trend_improved: input.recurrence?.thirty_day_trend_improved ?? null,
      previous_decision_id: input.recurrence?.previous_decision_id ?? null
    }
  };
}

function observationStats(observations) {
  return {
    count: observations.length,
    sessions: new Set(observations.map((observation) => observation.session_id)).size,
    days: new Set(observations.map((observation) => observation.day)).size
  };
}

function gate(passed, reason) {
  return Object.freeze({ passed, reason });
}

function rationaleFor({ policyClass, normalized, thresholdResults, hasCriticalFlag, recurredAfterSafeAuto, trendNotImproving }) {
  if (hasCriticalFlag) return `Critical approval is required because ${normalized.risk_flags.join(", ")} crosses the approved envelope.`;
  if (trendNotImproving) return "A blocking work item is required because the 30-day trend did not improve after the prior change.";
  if (recurredAfterSafeAuto) return "Bulk review is required because this friction class recurred after a prior safe-auto decision.";
  if (policyClass === "safe_auto_ready") return "Every ADR-0003 safe-auto threshold passed.";
  const failed = Object.entries(thresholdResults).filter(([, result]) => !result.passed).map(([name]) => name);
  return `Bulk review is required until these gates pass: ${failed.join(", ")}.`;
}

function founderSummaryFor({ policyClass, normalized, hasCriticalFlag, recurredAfterSafeAuto, trendNotImproving }) {
  if (hasCriticalFlag) return `Founder approval is required before ${normalized.action_category} because it touches a critical risk flag.`;
  if (trendNotImproving) return `A blocking work item is needed because ${normalized.friction_class} did not improve over 30 days.`;
  if (recurredAfterSafeAuto) return `Bulk review is required because ${normalized.friction_class} came back after a safe-auto change.`;
  if (policyClass === "safe_auto_ready") return `Safe auto is ready for ${normalized.action_category} because every enabled policy gate passed and rollback is defined.`;
  return `${normalized.action_category} is held for bulk review until missing policy gates are satisfied.`;
}

function bulkReviewKey(candidate) {
  return [candidate.action_category, candidate.friction_class, candidate.scope.project_id].join(":");
}

function expiryFrom(now) {
  const date = new Date(now);
  date.setUTCDate(date.getUTCDate() + 30);
  return date.toISOString();
}

function array(value) {
  return Array.isArray(value) ? value : [];
}

function required(value, field) {
  if (value == null || value === "") throw new Error(`${field} is required`);
  return value;
}
